3	const PBKDF2_ITERATIONS = 310_000;
4	const SALT_LENGTH = 16;
5	const IV_LENGTH = 12;
6	const KEY_BITS = 256;
7	
8	async function deriveKey(password: string, salt: Uint8Array): Promise<CryptoKey> {
9	  const encoder = new TextEncoder();
10	  const keyMaterial = await crypto.subtle.importKey(
11	    'raw',
12	    encoder.encode(password),
13	    'PBKDF2',
14	    false,
15	    ['deriveKey']
16	  );
17	
18	  return crypto.subtle.deriveKey(
19	    {
20	      name: 'PBKDF2',
21	      salt: salt as unknown as BufferSource,
22	      iterations: PBKDF2_ITERATIONS,
23	      hash: 'SHA-256',
24	    },
25	    keyMaterial,
26	    { name: 'AES-GCM', length: KEY_BITS },
27	    false,
28	    ['encrypt', 'decrypt']
29	  );
30	}
31	
32	function generateSalt(): Uint8Array {
33	  return crypto.getRandomValues(new Uint8Array(SALT_LENGTH));
34	}
35	
36	async function encrypt(
37	  key: CryptoKey,
38	  data: unknown
39	): Promise<{ ciphertext: ArrayBuffer; iv: Uint8Array }> {
40	  const encoder = new TextEncoder();
41	  const plaintext = encoder.encode(JSON.stringify(data));
42	  const iv = crypto.getRandomValues(new Uint8Array(IV_LENGTH));
43	
44	  const ciphertext = await crypto.subtle.encrypt(
45	    { name: 'AES-GCM', iv: iv as unknown as BufferSource },
46	    key,
47	    plaintext
48	  );
49	
50	  return { ciphertext, iv };
51	}
52	
53	async function decrypt(
54	  key: CryptoKey,
55	  ciphertext: ArrayBuffer,
56	  iv: Uint8Array
57	): Promise<unknown> {
58	  const decrypted = await crypto.subtle.decrypt(
59	    { name: 'AES-GCM', iv: iv as unknown as BufferSource },
60	    key,
61	    ciphertext
62	  );
63	
64	  const decoder = new TextDecoder();
65	  return JSON.parse(decoder.decode(decrypted));
66	}
67	
68	async function hashPassword(
69	  password: string,
70	  salt: Uint8Array
71	): Promise<ArrayBuffer> {
72	  const encoder = new TextEncoder();
73	  const keyMaterial = await crypto.subtle.importKey(
74	    'raw',
75	    encoder.encode(password),
76	    'PBKDF2',
77	    false,
78	    ['deriveBits']
79	  );
80	
81	  return crypto.subtle.deriveBits(
82	    {
83	      name: 'PBKDF2',
84	      salt: salt as unknown as BufferSource,
85	      iterations: PBKDF2_ITERATIONS,
86	      hash: 'SHA-256',
87	    },
88	    keyMaterial,
89	    KEY_BITS
90	  );
91	}
92	
93	async function reEncryptAll(
94	  userId: string,
95	  oldPassword: string,
96	  newPassword: string,
97	  getAllEncryptedRecords: () => Promise<
98	    Array<{ store: string; record: Record<string, unknown> }>
99	  >,
100	  writeRecords: (
101	    records: Array<{ store: string; record: Record<string, unknown> }>
102	  ) => Promise<void>,
103	  onProgress?: (current: number, total: number) => void
104	): Promise<void> {
105	  const flagKey = `encryption_migration_${userId}`;
106	  localStorage.setItem(flagKey, 'true');
107	
108	  try {
109	    const allRecords = await getAllEncryptedRecords();
110	    const total = allRecords.length;
111	
112	    // Derive old key from the first record's salt (stored on the user record)
113	    // The caller is responsible for including the user record which contains the salt
114	    const oldSalt = new Uint8Array(
115	      allRecords.find((r) => r.store === 'users')?.record['encryption_salt'] as ArrayBuffer
116	    );
117	    const oldKey = await deriveKey(oldPassword, oldSalt);
118	
119	    // Generate new salt and derive new key
120	    const newSalt = generateSalt();
121	    const newKey = await deriveKey(newPassword, newSalt);
122	
123	    const reEncryptedRecords: Array<{
124	      store: string;
125	      record: Record<string, unknown>;
126	    }> = [];
127	
128	    for (let i = 0; i < total; i++) {
129	      const { store, record } = allRecords[i];
130	
131	      if (record['ciphertext'] && record['iv']) {
132	        const plaintext = await decrypt(
133	          oldKey,
134	          record['ciphertext'] as ArrayBuffer,
135	          new Uint8Array(record['iv'] as ArrayBuffer)
136	        );
137	
138	        const { ciphertext, iv } = await encrypt(newKey, plaintext);
139	
140	        reEncryptedRecords.push({
141	          store,
142	          record: { ...record, ciphertext, iv },
143	        });
144	      } else if (store === 'users' && record['encryption_salt']) {
145	        // Update the user record with the new salt
146	        reEncryptedRecords.push({
147	          store,
148	          record: { ...record, encryption_salt: newSalt.buffer },
149	        });
150	      } else {
151	        reEncryptedRecords.push({ store, record });
152	      }
153	
154	      if (onProgress) {
155	        onProgress(i + 1, total);
156	      }
157	    }
158	
159	    await writeRecords(reEncryptedRecords);
160	    localStorage.removeItem(flagKey);
161	  } catch (error) {
162	    localStorage.removeItem(flagKey);
163	    throw error;
164	  }
165	}
166	
167	function isMigrationInProgress(userId: string): boolean {
168	  return localStorage.getItem(`encryption_migration_${userId}`) === 'true';
169	}
