11	type ChannelMessageMap = {
12	  'data-sync': DataSyncMessage;
13	  'auth-sync': AuthSyncMessage;
14	  'scheduler-sync': SchedulerSyncMessage;
15	  'registration-sync': RegistrationSyncMessage;
16	  'flag-sync': FlagSyncMessage;
