217	
218	function getDb(): IDBDatabase {
219	  if (!db) {
220	    throw new Error('IndexedDB not initialized. Call idbAccessLayer.init() first.');
221	  }
222	  return db;
223	}
224	
225	async function init(): Promise<void> {
226	  if (db) return;
227	
228	  if (!window.indexedDB) {
229	    throw new Error(
230	      'IndexedDB is not available. This application requires IndexedDB to function. ' +
231	      'If you are in private browsing mode, please switch to a regular window.'
232	    );
233	  }
234	
235	  return new Promise<void>((resolve, reject) => {
236	    const request = indexedDB.open(DB_NAME, DB_VERSION);
237	
238	    request.onerror = () => {
239	      reject(new Error(`Failed to open IndexedDB: ${request.error?.message}`));
240	    };
241	
242	    request.onupgradeneeded = (event) => {
243	      const database = (event.target as IDBOpenDBRequest).result;
244	
245	      for (const [storeName, definition] of Object.entries(STORE_DEFINITIONS)) {
246	        if (!database.objectStoreNames.contains(storeName)) {
247	          const store = database.createObjectStore(storeName, { keyPath: definition.keyPath });
248	          for (const index of definition.indexes) {
249	            store.createIndex(index.name, index.keyPath, index.options || {});
250	          }
251	        }
252	      }
253	    };
254	
255	    request.onsuccess = (event) => {
256	      db = (event.target as IDBOpenDBRequest).result;
257	
258	      db.onversionchange = () => {
259	        db?.close();
260	        db = null;
261	      };
262	
263	      // Initialize BroadcastChannel for data-sync
264	      try {
265	        dataSyncChannel = new BroadcastChannel('data-sync');
266	      } catch {
267	        console.warn('BroadcastChannel not supported. Cross-tab data sync disabled.');
268	      }
269	
270	      resolve();
271	    };
272	  });
273	}
