320	async function get<T = Record<string, unknown>>(store: string, key: string, userId?: string): Promise<T | undefined> {
321	  const database = getDb();
322	
323	  return new Promise<T | undefined>((resolve, reject) => {
324	    const tx = database.transaction(store, 'readonly');
325	    const objectStore = tx.objectStore(store);
326	    const request = objectStore.get(key);
327	
328	    request.onsuccess = async () => {
329	      const record = request.result;
330	      if (!record) {
331	        resolve(undefined);
332	        return;
333	      }
334	
335	      // Namespace filtering: if not a system store, check user_id
336	      if (!SYSTEM_STORES.has(store) && userId && record.user_id && record.user_id !== userId) {
337	        resolve(undefined);
338	        return;
339	      }
340	
341	      try {
342	        const decrypted = await maybeDecrypt(record, userId);
343	        resolve(decrypted as T);
344	      } catch (err) {
345	        reject(err);
346	      }
347	    };
348	
349	    request.onerror = () => reject(request.error);
350	  });
351	}
352	
353	async function getAll<T = Record<string, unknown>>(
354	  store: string,
355	  indexName?: string,
356	  query?: IDBKeyRange | IDBValidKey,
357	  userId?: string,
358	): Promise<T[]> {
359	  const database = getDb();
360	
361	  return new Promise<T[]>((resolve, reject) => {
362	    const tx = database.transaction(store, 'readonly');
363	    const objectStore = tx.objectStore(store);
364	    const source = indexName ? objectStore.index(indexName) : objectStore;
365	    const request = source.getAll(query);
366	
367	    request.onsuccess = async () => {
368	      let records: Record<string, unknown>[] = request.result;
369	
370	      // Namespace filtering
371	      if (!SYSTEM_STORES.has(store) && userId) {
372	        records = records.filter((r) => !r.user_id || r.user_id === userId);
373	      }
374	
375	      try {
376	        const decrypted = await Promise.all(records.map((r) => maybeDecrypt(r, userId)));
377	        resolve(decrypted as T[]);
378	      } catch (err) {
379	        reject(err);
380	      }
381	    };
382	
383	    request.onerror = () => reject(request.error);
384	  });
385	}
386	
387	async function put(store: string, record: Record<string, unknown>, userId?: string): Promise<{ version: number }> {
388	  const database = getDb();
389	  const storeDef = STORE_DEFINITIONS[store];
390	  if (!storeDef) throw new Error(`Unknown store: ${store}`);
391	
392	  const keyPath = storeDef.keyPath;
393	  const recordKey = getKeyPathValue(record, keyPath);
394	  const isVersioned = VERSIONED_STORES.has(store);
395	
396	  return new Promise<{ version: number }>((resolve, reject) => {
397	    const tx = database.transaction(store, 'readwrite');
398	    const objectStore = tx.objectStore(store);
399	
400	    // If versioned, do optimistic locking
401	    if (isVersioned) {
402	      const readRequest = objectStore.get(recordKey);
403	
404	      readRequest.onsuccess = async () => {
405	        const existing = readRequest.result;
406	
407	        if (existing) {
408	          // Optimistic locking: compare versions
409	          const existingVersion = existing._version as number;
410	          const expectedVersion = record._version as number;
411	
412	          if (expectedVersion !== undefined && expectedVersion !== existingVersion) {
413	            tx.abort();
414	            reject(new VersionConflictError(
415	              `Version conflict on ${store}/${recordKey}: expected ${expectedVersion}, found ${existingVersion}`
416	            ));
417	            return;
418	          }
419	
420	          record._version = existingVersion + 1;
421	        } else {
422	          // New record
423	          record._version = 1;
424	        }
425	
426	        try {
427	          const toWrite = await maybeEncrypt({ ...record }, userId);
428	          const writeRequest = objectStore.put(toWrite);
429	
430	          writeRequest.onsuccess = () => {
431	            broadcastChange('record-updated', store, recordKey, record._version as number, userId);
432	            resolve({ version: record._version as number });
433	          };
434	
435	          writeRequest.onerror = () => reject(writeRequest.error);
436	        } catch (err) {
437	          tx.abort();
438	          reject(err);
439	        }
440	      };
441	
442	      readRequest.onerror = () => reject(readRequest.error);
443	    } else {
444	      // Non-versioned store: direct put
445	      (async () => {
446	        try {
447	          const toWrite = await maybeEncrypt({ ...record }, userId);
448	          const writeRequest = objectStore.put(toWrite);
449	
450	          writeRequest.onsuccess = () => {
451	            broadcastChange('record-updated', store, recordKey, undefined, userId);
452	            resolve({ version: 0 });
453	          };
454	
455	          writeRequest.onerror = () => reject(writeRequest.error);
456	        } catch (err) {
457	          tx.abort();
458	          reject(err);
459	        }
460	      })();
461	    }
462	
463	    tx.onerror = () => {
464	      if (tx.error?.name !== 'AbortError') {
465	        reject(tx.error);
466	      }
467	    };
468	  });
469	}
470	
471	async function del(store: string, key: string, userId?: string): Promise<void> {
472	  const database = getDb();
473	
474	  return new Promise<void>((resolve, reject) => {
475	    const tx = database.transaction(store, 'readwrite');
476	    const objectStore = tx.objectStore(store);
477	
478	    // If namespace filtering, verify ownership before deleting
479	    if (!SYSTEM_STORES.has(store) && userId) {
480	      const readRequest = objectStore.get(key);
481	      readRequest.onsuccess = () => {
482	        const existing = readRequest.result;
483	        if (!existing) {
484	          resolve();
485	          return;
486	        }
487	        if (existing.user_id && existing.user_id !== userId) {
488	          reject(new Error('Access denied: cannot delete record owned by another user'));
489	          return;
490	        }
491	        const deleteRequest = objectStore.delete(key);
492	        deleteRequest.onsuccess = () => {
493	          broadcastChange('record-deleted', store, key, undefined, userId);
494	          resolve();
495	        };
496	        deleteRequest.onerror = () => reject(deleteRequest.error);
497	      };
498	      readRequest.onerror = () => reject(readRequest.error);
499	    } else {
500	      const request = objectStore.delete(key);
501	      request.onsuccess = () => {
502	        broadcastChange('record-deleted', store, key, undefined, userId);
503	        resolve();
504	      };
505	      request.onerror = () => reject(request.error);
506	    }
507	  });
508	}
