510	/**
511	 * Execute a function within an IndexedDB transaction spanning one or more stores.
512	 * The function receives a helper object with get/getAll/put/delete methods scoped to the transaction.
513	 * All operations within the function are atomic.
514	 */
515	async function transaction<T>(
516	  storeNames: string[],
517	  mode: IDBTransactionMode,
518	  fn: (helpers: TransactionHelpers) => Promise<T>,
519	): Promise<T> {
520	  const database = getDb();
521	
522	  return new Promise<T>((resolve, reject) => {
523	    const tx = database.transaction(storeNames, mode);
524	    let result: T;
525	    let completed = false;
526	
527	    const helpers: TransactionHelpers = {
528	      getStore(storeName: string): IDBObjectStore {
529	        return tx.objectStore(storeName);
530	      },
531	
532	      get<R = Record<string, unknown>>(storeName: string, key: string): Promise<R | undefined> {
533	        return new Promise((res, rej) => {
534	          const store = tx.objectStore(storeName);
535	          const request = store.get(key);
536	          request.onsuccess = () => res(request.result as R | undefined);
537	          request.onerror = () => rej(request.error);
538	        });
539	      },
540	
541	      getAll<R = Record<string, unknown>>(storeName: string, indexName?: string, query?: IDBKeyRange | IDBValidKey): Promise<R[]> {
542	        return new Promise((res, rej) => {
543	          const store = tx.objectStore(storeName);
544	          const source = indexName ? store.index(indexName) : store;
545	          const request = source.getAll(query);
546	          request.onsuccess = () => res(request.result as R[]);
547	          request.onerror = () => rej(request.error);
548	        });
549	      },
550	
551	      put(storeName: string, record: Record<string, unknown>): Promise<void> {
552	        return new Promise((res, rej) => {
553	          const store = tx.objectStore(storeName);
554	          const request = store.put(record);
555	          request.onsuccess = () => res();
556	          request.onerror = () => rej(request.error);
557	        });
558	      },
559	
560	      delete(storeName: string, key: string): Promise<void> {
561	        return new Promise((res, rej) => {
562	          const store = tx.objectStore(storeName);
563	          const request = store.delete(key);
564	          request.onsuccess = () => res();
565	          request.onerror = () => rej(request.error);
566	        });
567	      },
568	
569	      abort(): void {
570	        tx.abort();
571	      },
572	    };
573	
574	    tx.oncomplete = () => {
575	      completed = true;
576	      resolve(result);
577	    };
578	
579	    tx.onerror = () => {
580	      if (!completed) {
581	        reject(tx.error);
582	      }
583	    };
584	
585	    tx.onabort = () => {
586	      if (!completed) {
587	        reject(tx.error || new Error('Transaction aborted'));
588	      }
589	    };
590	
591	    // Execute the user function
592	    fn(helpers)
593	      .then((r) => {
594	        result = r;
595	      })
596	      .catch((err) => {
597	        try { tx.abort(); } catch { /* already aborted */ }
598	        reject(err);
599	      });
600	  });
601	}
