    font-weight: 600;
    font-size: 1rem;
  }

  .top-bar-actions {
    margin-left: auto;
    display: flex;
    align-items: center;
    gap: 0.5rem;
  }

  .icon-btn {
    position: relative;
    background: none;
    border: none;
    color: white;
    font-size: 1.125rem;
    cursor: pointer;
    padding: 0.25rem 0.5rem;
    border-radius: 4px;
  }

  .icon-btn:hover {
    background: rgba(255, 255, 255, 0.1);
  }

  .badge {
    position: absolute;
    top: -4px;
    right: -4px;
    background: #ef4444;
