    min-width: 16px;
    text-align: center;
  }

  .user-info {
    font-size: 0.8rem;
    opacity: 0.8;
    text-transform: capitalize;
  }

  .logout-btn {
    background: rgba(255, 255, 255, 0.1);
    border: 1px solid rgba(255, 255, 255, 0.2);
    color: white;
    padding: 0.25rem 0.75rem;
    border-radius: 4px;
    font-size: 0.8rem;
    cursor: pointer;
  }

  .logout-btn:hover {
    background: rgba(255, 255, 255, 0.2);
  }

  .sidebar {
    grid-area: sidebar;
    background: #f8fafc;
    border-right: 1px solid #e2e8f0;
    padding: 0.5rem;
    overflow-y: auto;
  }

  .nav-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.5rem 0.75rem;
    border-radius: 6px;
    color: #475569;
    text-decoration: none;
    font-size: 0.875rem;
    margin-bottom: 2px;
    transition: background 0.1s;
  }

  .nav-item:hover {
    background: #e2e8f0;
  }

  .nav-item.active {
    background: #dbeafe;
    color: #1e40af;
