  import { onMount, onDestroy } from 'svelte';
  import { authStore } from './lib/stores';
  import { registerRoutes, startRouter, resolvedRoute } from './lib/utils/router';
  import { routeDefinitions } from './lib/config/routes';
  import RouteGuard from './lib/components/RouteGuard.svelte';
  import AppShell from './lib/components/AppShell.svelte';

  let initialized = $state(false);
  let initError = $state('');
  let stopRouter: (() => void) | undefined;

  onMount(async () => {
    try {
      // Initialize IndexedDB
      const { idbAccessLayer } = await import('./lib/services/idbAccessLayer');
      await idbAccessLayer.init();

      // Register routes
      registerRoutes(routeDefinitions);

      // Restore session
      const { authService } = await import('./lib/services/authService');
      authService.restoreSession();

      // Initialize cross-tab auth sync
      authService.initCrossTabSync();

      // Start router
      stopRouter = startRouter();

      initialized = true;
    } catch (err: any) {
      initError = err.message || 'Failed to initialize application';
      console.error('Init error:', err);
    }
  });

  onDestroy(() => {
    stopRouter?.();
  });
</script>

{#if initError}
  <div class="init-error">
    <h2>Application Error</h2>
    <p>{initError}</p>
    <p>Please ensure your browser supports IndexedDB and try refreshing the page.</p>
  </div>
{:else if !initialized}
  <div class="loading">
    <p>Loading application...</p>
  </div>
{:else}
  <RouteGuard>
    <AppShell>
      {#if $resolvedRoute.component}
        <svelte:component this={$resolvedRoute.component} params={$resolvedRoute.params} />
      {:else}
        <div class="not-found">
          <h2>Page Not Found</h2>
          <p>The requested page does not exist.</p>
        </div>
      {/if}
    </AppShell>
  </RouteGuard>
{/if}

<style>
  .init-error {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    padding: 2rem;
    text-align: center;
    color: #dc2626;
  }

  .loading {
    display: flex;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    color: #666;
  }

  .not-found {
    text-align: center;
    padding: 3rem;
    color: #666;
  }
</style>
"}

