            onkeydown={(e) => { if (e.key === 'Enter') handleRowClick(booking.booking_id); }}
          >
            <td>{booking.room_id}</td>
            <td>{formatDate(booking.start_time)}</td>
            <td>{formatTime(booking.start_time)} &ndash; {formatTime(booking.end_time)}</td>
            <td>
