7	// Monthly Bill Generation
8	// ============================================================
9	
10	async function generateMonthlyBills(): Promise<Bill[]> {
11	  // RBAC — allow SYSTEM_ADMIN / OPS_COORDINATOR
12	  rbacService.checkRole(['SYSTEM_ADMIN', 'OPS_COORDINATOR']);
13	
14	  // Read configuration values up-front (async, outside transaction)
15	  const housingFeeRaw = await opsConfigService.getPolicy('housing_fee');
16	  const housing_fee = typeof housingFeeRaw === 'number' ? housingFeeRaw : 950;
17	
18	  const rateRaw = await opsConfigService.getPolicy('rate_per_unit');
19	  const rate_per_unit = typeof rateRaw === 'number' ? rateRaw : 2.0;
20	
21	  // Load participants
22	  const participants = await idbAccessLayer.getAll<User>('users', 'idx_role', 'PARTICIPANT');
23	
24	  // Load all billing registry entries (meter readings)
25	  const registryEntries = await idbAccessLayer.getAll<BillingRegistry>('billing_registry');
26	
27	  const billing_period = new Date().toISOString().slice(0, 7); // "YYYY-MM"
28	  const bills: Bill[] = [];
29	
30	  for (const user of participants) {
31	    // Find meter reading for this participant
32	    const meterEntry = registryEntries.find((r) => r.participant_id === user.user_id);
33	    let utility_charge = 0;
34	
35	    if (!meterEntry || meterEntry.meter_reading === 0) {
36	      console.warn(
37	        `[billingService] Missing or zero meter reading for participant ${user.user_id}. Utility charge set to 0.`,
38	      );
39	    } else {
40	      utility_charge = meterEntry.meter_reading * rate_per_unit;
41	    }
42	
43	    const subtotal = housing_fee + utility_charge;
44	
45	    // Load active waivers for this participant
46	    const allWaivers = await idbAccessLayer.getAll<Waiver>('waivers', 'idx_participant', user.user_id);
47	    const activeWaivers = allWaivers.filter((w) => w.status === 'active');
48	
49	    // Separate fixed vs percentage waivers
50	    const fixedWaivers = activeWaivers.filter((w) => w.waiver_type === 'fixed');
51	    const percentageWaivers = activeWaivers.filter((w) => w.waiver_type === 'percentage');
52	
53	    // Apply fixed waivers first
54	    let total = subtotal;
55	    for (const fw of fixedWaivers) {
56	      total -= fw.value;
57	    }
58	
59	    // Apply percentage waivers on the remainder
60	    for (const pw of percentageWaivers) {
61	      total *= 1 - pw.value / 100;
62	    }
63	
64	    // Cap at 0 — no negative bills
65	    if (total < 0) {
66	      console.warn(
67	        `[billingService] Waivers caused negative total (${total}) for participant ${user.user_id}. Capping at 0.`,
68	      );
69	      total = 0;
70	    }
71	
72	    const waiver_amount = housing_fee + utility_charge - total;
73	
74	    const bill: Bill = {
75	      bill_id: crypto.randomUUID(),
76	      participant_id: user.user_id,
77	      billing_period,
78	      housing_fee,
79	      utility_charge,
80	      waiver_amount,
81	      total,
82	      status: 'generated',
83	      due_date: Date.now() + 10 * 24 * 60 * 60 * 1000,
84	      generated_at: Date.now(),
85	      _version: 1,
86	    };
87	
88	    await idbAccessLayer.put('bills', bill as any);
89	    bills.push(bill);
90	
91	    // Reset meter reading to 0
92	    if (meterEntry) {
93	      await idbAccessLayer.put('billing_registry', {
94	        ...meterEntry,
95	        meter_reading: 0,
96	        _version: meterEntry._version + 1,
97	      } as any);
98	    }
99	  }
100	
101	  return bills;
102	}
