1	import { writable, derived, get } from 'svelte/store';
2	import type { Role } from '../types';
3	
4	// ============================================================
5	// Route Definition
6	// ============================================================
7	
8	export interface RouteDefinition {
9	  path: string;
10	  component: () => Promise<{ default: any }>;
11	  roles: Role[] | 'public';
12	}
13	
14	// ============================================================
15	// Router State
16	// ============================================================
17	
18	export const currentPath = writable(getHashPath());
19	export const currentParams = writable<Record<string, string>>({});
20	export const currentQuery = writable<Record<string, string>>({});
21	
22	function getHashPath(): string {
23	  const hash = window.location.hash.slice(1) || '/login';
24	  const questionIndex = hash.indexOf('?');
25	  return questionIndex >= 0 ? hash.slice(0, questionIndex) : hash;
26	}
27	
28	function getHashQuery(): Record<string, string> {
29	  const hash = window.location.hash.slice(1) || '';
30	  const questionIndex = hash.indexOf('?');
31	  if (questionIndex < 0) return {};
32	  const params = new URLSearchParams(hash.slice(questionIndex + 1));
33	  const result: Record<string, string> = {};
34	  params.forEach((v, k) => { result[k] = v; });
35	  return result;
36	}
37	
38	// ============================================================
39	// Route Registry
40	// ============================================================
41	
42	const routes: RouteDefinition[] = [];
43	
44	export function registerRoutes(defs: RouteDefinition[]): void {
45	  routes.length = 0;
46	  routes.push(...defs);
47	}
48	
49	// ============================================================
50	// Route Matching
51	// ============================================================
52	
53	interface MatchResult {
54	  route: RouteDefinition;
55	  params: Record<string, string>;
56	}
57	
58	function matchRoute(path: string): MatchResult | null {
59	  for (const route of routes) {
60	    const params = matchPath(route.path, path);
61	    if (params !== null) {
62	      return { route, params };
63	    }
64	  }
65	  return null;
66	}
67	
68	function matchPath(pattern: string, path: string): Record<string, string> | null {
69	  const patternParts = pattern.split('/').filter(Boolean);
70	  const pathParts = path.split('/').filter(Boolean);
71	
72	  if (patternParts.length !== pathParts.length) return null;
73	
74	  const params: Record<string, string> = {};
75	
76	  for (let i = 0; i < patternParts.length; i++) {
77	    const pp = patternParts[i];
78	    const pathPart = pathParts[i];
79	
80	    if (pp.startsWith(':')) {
81	      params[pp.slice(1)] = pathPart;
82	    } else if (pp !== pathPart) {
83	      return null;
84	    }
85	  }
86	
87	  return params;
88	}
89	
90	// ============================================================
91	// Navigation
92	// ============================================================
93	
94	export function navigate(path: string, query?: Record<string, string>): void {
95	  let hash = path;
96	  if (query && Object.keys(query).length > 0) {
97	    const params = new URLSearchParams(query);
98	    hash += '?' + params.toString();
99	  }
100	  window.location.hash = hash;
101	}
102	
103	export function replaceRoute(path: string, query?: Record<string, string>): void {
104	  let hash = '#' + path;
105	  if (query && Object.keys(query).length > 0) {
106	    const params = new URLSearchParams(query);
107	    hash += '?' + params.toString();
108	  }
109	  window.history.replaceState(null, '', hash);
110	  currentPath.set(path);
111	  currentParams.set({});
112	  currentQuery.set(query || {});
113	}
114	
115	// ============================================================
116	// Resolve current route
117	// ============================================================
118	
119	export interface ResolvedRoute {
120	  route: RouteDefinition | null;
121	  params: Record<string, string>;
122	  component: any | null;
123	}
124	
125	export const resolvedRoute = writable<ResolvedRoute>({
126	  route: null,
127	  params: {},
128	  component: null,
129	});
130	
131	export async function resolveCurrentRoute(): Promise<ResolvedRoute> {
132	  const path = get(currentPath);
133	  const match = matchRoute(path);
134	
135	  if (!match) {
136	    const result = { route: null, params: {}, component: null };
137	    resolvedRoute.set(result);
138	    return result;
139	  }
140	
141	  currentParams.set(match.params);
142	
143	  try {
144	    const mod = await match.route.component();
145	    const result = { route: match.route, params: match.params, component: mod.default };
146	    resolvedRoute.set(result);
147	    return result;
148	  } catch {
149	    const result = { route: match.route, params: match.params, component: null };
150	    resolvedRoute.set(result);
151	    return result;
152	  }
153	}
154	
155	/**
156	 * Get the permitted roles for a given path.
157	 */
158	export function getRouteRoles(path: string): Role[] | 'public' | null {
159	  const match = matchRoute(path);
160	  return match ? match.route.roles : null;
161	}
162	
163	// ============================================================
164	// Hash Change Listener
165	// ============================================================
166	
167	let listening = false;
168	
169	export function startRouter(): () => void {
170	  if (listening) return () => {};
171	
172	  const handler = () => {
173	    currentPath.set(getHashPath());
174	    currentQuery.set(getHashQuery());
175	    resolveCurrentRoute();
176	  };
177	
178	  window.addEventListener('hashchange', handler);
179	  listening = true;
180	
181	  // Initial resolve
182	  handler();
183	
184	  return () => {
185	    window.removeEventListener('hashchange', handler);
186	    listening = false;
187	  };
188	}
