10	async function loadDefaults(): Promise<void> {
11	  try {
12	    for (const [key, value] of Object.entries(defaults)) {
13	      const existing = await idbAccessLayer.get<Configuration>('configuration', key);
14	      if (!existing) {
15	        await idbAccessLayer.put('configuration', {
16	          config_key: key,
17	          value,
18	          updated_at: Date.now(),
19	          updated_by: 'system',
20	        });
21	      }
22	    }
23	  } catch (err) {
24	    console.warn('Failed to load config from JSON, using hardcoded defaults:', err);
25	    // Hardcoded fallbacks for critical values
26	    const hardcoded: Record<string, unknown> = {
27	      housing_fee: 950,
28	      rate_per_unit: 2.0,
29	      booking_window_days: 14,
30	      max_active_reservations: 3,
31	      lockout_duration_minutes: 15,
32	      max_login_attempts: 10,
33	      rate_limit_attempts: 5,
34	      rate_limit_window_seconds: 10,
35	      overdue_days: 10,
36	      dnd_start: '22:00',
37	      dnd_end: '07:00',
38	      pbkdf2_iterations: 310000,
39	    };
40	    for (const [key, value] of Object.entries(hardcoded)) {
41	      const existing = await idbAccessLayer.get<Configuration>('configuration', key);
42	      if (!existing) {
43	        await idbAccessLayer.put('configuration', {
44	          config_key: key,
45	          value,
46	          updated_at: Date.now(),
47	          updated_by: 'system',
48	        });
49	      }
50	    }
51	  }
52	}
