54	async function getPolicy(key: string): Promise<unknown> {
55	  const record = await idbAccessLayer.get<Configuration>('configuration', key);
56	  if (record) return record.value;
57	  // Fallback to defaults.json
58	  const def = (defaults as Record<string, unknown>)[key];
59	  return def !== undefined ? def : null;
60	}
61	
62	async function setPolicy(key: string, value: unknown): Promise<void> {
63	  rbacService.checkPermission('policy:modify');
64	
65	  // Validate
66	  if (key === 'booking_window_days' && (typeof value !== 'number' || value < 1)) {
67	    throw new Error('Booking window must be a positive number');
68	  }
69	  if (key === 'max_active_reservations' && (typeof value !== 'number' || value < 1)) {
70	    throw new Error('Max active reservations must be a positive number');
71	  }
72	  if (key === 'housing_fee' && (typeof value !== 'number' || value < 0)) {
73	    throw new Error('Housing fee cannot be negative');
74	  }
75	  if (key === 'rate_per_unit' && (typeof value !== 'number' || value < 0)) {
76	    throw new Error('Rate per unit cannot be negative');
77	  }
78	
79	  const session = rbacService.getCurrentSession();
80	  const existing = await idbAccessLayer.get<Configuration>('configuration', key);
81	
82	  await idbAccessLayer.put('configuration', {
83	    config_key: key,
84	    value,
85	    updated_at: Date.now(),
86	    updated_by: session.user_id,
87	  });
88	}
89	
90	async function getAllPolicies(): Promise<Configuration[]> {
91	  return idbAccessLayer.getAll<Configuration>('configuration');
92	}
