95	// Maintenance Windows
96	// ============================================================
97	
98	async function createMaintenanceWindow(input: MaintenanceWindowInput): Promise<MaintenanceWindow> {
99	  rbacService.checkRole(['SYSTEM_ADMIN', 'OPS_COORDINATOR']);
100	
101	  if (input.start_time >= input.end_time) {
102	    throw new Error('Maintenance window start time must be before end time');
103	  }
104	
105	  const window: MaintenanceWindow = {
106	    window_id: crypto.randomUUID(),
107	    room_id: input.room_id,
108	    start_time: input.start_time,
109	    end_time: input.end_time,
110	    description: input.description,
111	    _version: 1,
112	  };
113	
114	  await idbAccessLayer.put('maintenance_windows', window);
115	
116	  // Check for overlapping confirmed bookings and flag them
117	  const bookings = await idbAccessLayer.getAll('bookings');
118	  const overlapping = bookings.filter(
119	    (b: any) =>
120	      b.room_id === input.room_id &&
121	      b.status !== 'cancelled' &&
122	      b.start_time < input.end_time &&
123	      b.end_time > input.start_time
124	  );
125	
126	  if (overlapping.length > 0) {
127	    console.warn(
128	      `Maintenance window overlaps ${overlapping.length} existing booking(s). ` +
129	      `Affected booking IDs: ${overlapping.map((b: any) => b.booking_id).join(', ')}`
130	    );
131	  }
132	
133	  return window;
134	}
135	
136	async function updateMaintenanceWindow(windowId: string, updates: Partial<MaintenanceWindowInput>): Promise<MaintenanceWindow> {
137	  rbacService.checkRole(['SYSTEM_ADMIN', 'OPS_COORDINATOR']);
138	
139	  const existing = await idbAccessLayer.get<MaintenanceWindow>('maintenance_windows', windowId);
140	  if (!existing) throw new Error(`Maintenance window ${windowId} not found`);
141	
142	  const updated: MaintenanceWindow = {
143	    ...existing,
144	    ...updates,
145	  };
146	
147	  if (updated.start_time >= updated.end_time) {
148	    throw new Error('Maintenance window start time must be before end time');
149	  }
150	
151	  await idbAccessLayer.put('maintenance_windows', updated);
152	  return updated;
153	}
154	
155	async function deleteMaintenanceWindow(windowId: string): Promise<void> {
156	  rbacService.checkRole(['SYSTEM_ADMIN', 'OPS_COORDINATOR']);
157	  await idbAccessLayer.delete('maintenance_windows', windowId);
158	}
159	
160	async function getMaintenanceWindows(roomId?: string): Promise<MaintenanceWindow[]> {
161	  if (roomId) {
162	    return idbAccessLayer.getAll<MaintenanceWindow>('maintenance_windows', 'idx_room', roomId);
163	  }
164	  return idbAccessLayer.getAll<MaintenanceWindow>('maintenance_windows');
165	}
