182	    target_id: targetId,
183	    reason,
184	    created_by: session.user_id,
185	    created_at: Date.now(),
186	    _version: 1,
187	  };
188	
189	  await idbAccessLayer.put('blacklist_rules', rule);
190	  return rule;
191	}
