202	async function isBlacklisted(targetType: 'participant' | 'room', targetId: string): Promise<boolean> {
203	  const rules = await idbAccessLayer.getAll<BlacklistRule>('blacklist_rules', 'idx_target_type', targetType);
204	  return rules.some((r) => r.target_id === targetId);
