6	const STORE = 'feature_flags';
7	
8	// In-memory cache
9	const cache = new Map<string, FeatureFlag>();
10	
11	let unsubscribe: (() => void) | null = null;
12	
13	async function initialize(context?: { role: string; org_unit: string }): Promise<void> {
14	  const flags = await idbAccessLayer.getAll<FeatureFlag>(STORE);
15	
16	  cache.clear();
17	  for (const flag of flags) {
18	    cache.set(flag.flag_id, flag);
19	  }
20	
21	  if (context) {
22	    refreshFlagStore(context);
23	  }
24	
25	  // Subscribe to cross-tab flag sync for cache invalidation
26	  if (unsubscribe) {
27	    unsubscribe();
28	  }
29	
30	  unsubscribe = channelManager.onMessage(CHANNELS.FLAG_SYNC, async (message: FlagSyncMessage) => {
31	    if (message.type === 'flag-changed') {
32	      // Re-read the flag from IndexedDB to get the latest state
33	      const updated = await idbAccessLayer.get<FeatureFlag>(STORE, message.flag_id);
34	      if (updated) {
35	        cache.set(updated.flag_id, updated);
36	      } else {
37	        cache.delete(message.flag_id);
38	      }
39	
40	      if (context) {
41	        refreshFlagStore(context);
42	      }
43	    }
44	  });
45	}
46	
47	function evaluateFlag(flagId: string, context: { role: string; org_unit: string }): boolean {
48	  const flag = cache.get(flagId);
49	  if (!flag) return false;
50	
51	  if (!flag.enabled) return false;
52	
53	  if (flag.target_roles.length > 0 && !flag.target_roles.includes(context.role as Role)) {
54	    return false;
55	  }
56	
57	  if (flag.target_org_units.length > 0 && !flag.target_org_units.includes(context.org_unit)) {
58	    return false;
59	  }
60	
61	  return true;
62	}
63	
64	function refreshFlagStore(context: { role: string; org_unit: string }): void {
65	  const result: Record<string, boolean> = {};
66	  for (const [flagId, _flag] of cache) {
67	    result[flagId] = evaluateFlag(flagId, context);
68	  }
69	  flagStore.set(result);
70	}
71	
72	async function createFlag(flag: FlagInput, createdBy: string): Promise<FeatureFlag> {
73	  const now = Date.now();
74	  const fullFlag: FeatureFlag = {
75	    flag_id: flag.flag_id,
76	    display_name: flag.display_name,
77	    description: flag.description,
78	    enabled: flag.enabled,
79	    target_roles: flag.target_roles,
80	    target_org_units: flag.target_org_units,
81	    created_by: createdBy,
82	    created_at: now,
83	    updated_at: now,
84	  };
85	
86	  await idbAccessLayer.put(STORE, fullFlag as unknown as Record<string, unknown>);
87	  cache.set(fullFlag.flag_id, fullFlag);
88	
89	  channelManager.broadcast(CHANNELS.FLAG_SYNC, {
90	    type: 'flag-changed',
91	    flag_id: fullFlag.flag_id,
92	    enabled: fullFlag.enabled,
93	    target_roles: fullFlag.target_roles,
94	    target_org_units: fullFlag.target_org_units,
95	  });
96	
97	  return fullFlag;
98	}
99	
100	async function updateFlag(flagId: string, updates: Partial<FeatureFlag>): Promise<void> {
101	  const current = await idbAccessLayer.get<FeatureFlag>(STORE, flagId);
102	  if (!current) {
103	    throw new Error(`Flag not found: ${flagId}`);
104	  }
105	
106	  const merged: FeatureFlag = {
107	    ...current,
108	    ...updates,
109	    flag_id: current.flag_id, // prevent overwriting the key
110	    updated_at: Date.now(),
111	  };
112	
113	  await idbAccessLayer.put(STORE, merged as unknown as Record<string, unknown>);
114	  cache.set(flagId, merged);
115	
116	  channelManager.broadcast(CHANNELS.FLAG_SYNC, {
117	    type: 'flag-changed',
118	    flag_id: merged.flag_id,
119	    enabled: merged.enabled,
120	    target_roles: merged.target_roles,
121	    target_org_units: merged.target_org_units,
122	  });
123	}
124	
125	async function deleteFlag(flagId: string): Promise<void> {
126	  await idbAccessLayer.delete(STORE, flagId);
127	  cache.delete(flagId);
128	
129	  channelManager.broadcast(CHANNELS.FLAG_SYNC, {
130	    type: 'flag-changed',
131	    flag_id: flagId,
132	    enabled: false,
133	    target_roles: [],
134	    target_org_units: [],
135	  });
136	}
137	
138	function getAllFlags(): FeatureFlag[] {
139	  return Array.from(cache.values());
140	}
141	
142	export const featureFlagService = {
143	  initialize,
144	  evaluateFlag,
145	  refreshFlagStore,
146	  createFlag,
147	  updateFlag,
148	  deleteFlag,
149	  getAllFlags,
150	};
151	
152	export default featureFlagService;
153

1	import { get } from 'svelte/store';
2	import { idbAccessLayer } from './idbAccessLayer';
3	import { encryptionService } from './encryptionService';
4	import { channelManager, CHANNELS } from '../utils/broadcastChannels';
5	import { authStore } from '../stores';
6	import type { Session, User, AuthSyncMessage, Role } from '../types';
7	
8	// ============================================================
9	// Helpers
10	// ============================================================
11	
12	function compareBuffers(a: ArrayBuffer, b: ArrayBuffer): boolean {
13	  const viewA = new Uint8Array(a);
14	  const viewB = new Uint8Array(b);
15	  if (viewA.byteLength !== viewB.byteLength) return false;
16	  for (let i = 0; i < viewA.byteLength; i++) {
17	    if (viewA[i] !== viewB[i]) return false;
18	  }
19	  return true;
20	}
21	
22	// ============================================================
23	// 1. login
24	// ============================================================
25	
26	async function login(username: string, password: string): Promise<Session> {
27	  const users: User[] = await idbAccessLayer.getAll('users', 'idx_username', username);
28	  const user = users[0];
29	  if (!user) {
30	    throw new Error('Invalid username or password');
31	  }
32	
33	  // Check account lockout
34	  if (user.locked_until && user.locked_until > Date.now()) {
35	    const remainingMs = user.locked_until - Date.now();
36	    const remainingMin = Math.ceil(remainingMs / 60_000);
37	    throw new Error(
38	      `Account is locked. Try again in ${remainingMin} minute${remainingMin !== 1 ? 's' : ''}.`
39	    );
40	  }
41	
42	  // Derive hash and compare
43	  const hash = await encryptionService.hashPassword(
44	    password,
45	    new Uint8Array(user.salt) as unknown as Uint8Array
46	  );
47	
48	  if (!compareBuffers(hash, user.password_hash)) {
49	    // Mismatch — increment failed_attempts
50	    const newAttempts = user.failed_attempts + 1;
51	    const updatedUser: User = {
52	      ...user,
53	      failed_attempts: newAttempts,
54	      locked_until: newAttempts >= 10 ? Date.now() + 15 * 60 * 1000 : user.locked_until,
55	    };
56	    await idbAccessLayer.put('users', updatedUser);
57	    throw new Error('Invalid username or password');
58	  }
59	
60	  // Match — reset failed_attempts
61	  const clearedUser: User = {
62	    ...user,
63	    failed_attempts: 0,
64	    locked_until: null,
65	  };
66	  await idbAccessLayer.put('users', clearedUser);
67	
68	  // Build session
69	  const session: Session = {
70	    user_id: user.user_id,
71	    role: user.role,
72	    org_unit: user.org_unit,
73	    token: crypto.randomUUID(),
74	    expires_at: Date.now() + 24 * 60 * 60 * 1000,
75	  };
76	
77	  localStorage.setItem(`session_${user.user_id}`, JSON.stringify(session));
78	  authStore.set(session);
79	
80	  return session;
81	}
82	
83	// ============================================================
84	// 2. logout
85	// ============================================================
86	
87	async function logout(): Promise<void> {
88	  const session = get(authStore);
89	
90	  if (session) {
91	    localStorage.removeItem(`session_${session.user_id}`);
92	    channelManager.broadcast(CHANNELS.AUTH_SYNC, {
93	      type: 'logout',
94	      user_id: session.user_id,
95	    });
96	  }
97	
98	  authStore.set(null);
99	}
100	
101	// ============================================================
102	// 3. restoreSession
103	// ============================================================
104	
105	function restoreSession(): Session | null {
106	  try {
107	    for (let i = 0; i < localStorage.length; i++) {
108	      const key = localStorage.key(i);
109	      if (key && key.startsWith('session_')) {
110	        const raw = localStorage.getItem(key);
111	        if (raw) {
112	          const parsed: Session = JSON.parse(raw);
113	          if (parsed.expires_at > Date.now()) {
114	            authStore.set(parsed);
115	            return parsed;
116	          }
117	          // Stale — remove
118	          localStorage.removeItem(key);
119	        }
120	      }
121	    }
122	  } catch {
123	    // localStorage may be unavailable
124	  }
125	  return null;
126	}
127	
128	// ============================================================
129	// 4. changePassword
130	// ============================================================
131	
132	async function changePassword(
133	  userId: string,
134	  oldPassword: string,
135	  newPassword: string
136	): Promise<void> {
137	  const user: User | undefined = await idbAccessLayer.get('users', userId);
138	  if (!user) {
139	    throw new Error('User not found');
140	  }
141	
142	  // Verify old password
143	  const oldHash = await encryptionService.hashPassword(
144	    oldPassword,
145	    new Uint8Array(user.salt) as unknown as Uint8Array
146	  );
147	
148	  if (!compareBuffers(oldHash, user.password_hash)) {
149	    throw new Error('Current password is incorrect');
150	  }
151	
152	  // Generate new credentials
153	  const newSalt = encryptionService.generateSalt();
154	  const newHash = await encryptionService.hashPassword(newPassword, newSalt);
155	
156	  // Re-encrypt if encryption is enabled
157	  if (user.encryption_enabled) {
158	    await encryptionService.reEncryptAll(
159	      userId,
160	      oldPassword,
161	      newPassword,
162	      async () => {
163	        // Gather all encrypted records for this user — include user record itself
164	        const allStores = ['users'];
165	        const records: Array<{ store: string; record: Record<string, unknown> }> = [];
166	        const currentUser = await idbAccessLayer.get('users', userId);
167	        if (currentUser) {
168	          records.push({ store: 'users', record: currentUser as unknown as Record<string, unknown> });
169	        }
170	        return records;
171	      },
172	      async (records) => {
173	        for (const { store, record } of records) {
174	          await idbAccessLayer.put(store, record);
175	        }
176	      }
177	    );
178	  }
179	
180	  // Update user record
181	  const updatedUser: User = {
182	    ...user,
183	    password_hash: newHash,
184	    salt: newSalt.buffer as ArrayBuffer,
185	    _version: user._version + 1,
186	  };
187	  await idbAccessLayer.put('users', updatedUser);
188	
189	  // Broadcast session refresh
190	  channelManager.broadcast(CHANNELS.AUTH_SYNC, {
191	    type: 'session-refresh',
192	    user_id: userId,
193	  });
194	}
195	
196	// ============================================================
197	// 5. initCrossTabSync
198	// ============================================================
199	
200	function initCrossTabSync(): () => void {
201	  const unsubscribe = channelManager.onMessage(
202	    CHANNELS.AUTH_SYNC,
203	    (message: AuthSyncMessage) => {
204	      if (message.type === 'logout') {
205	        // Clear local session for the user
206	        localStorage.removeItem(`session_${message.user_id}`);
207	        authStore.set(null);
208	      } else if (message.type === 'session-refresh') {
209	        const current = get(authStore);
210	        if (current && current.user_id === message.user_id) {
211	          const updated: Session = {
212	            ...current,
213	            expires_at: message.new_expires_at ?? current.expires_at,
214	          };
215	          authStore.set(updated);
216	          localStorage.setItem(`session_${current.user_id}`, JSON.stringify(updated));
217	        }
218	      }
219	    }
220	  );
221	
222	  return unsubscribe;
223	}
224	
225	// ============================================================
226	// 6. createUser
227	// ============================================================
228	
229	async function createUser(userData: {
230	  username: string;
231	  password: string;
232	  role: Role;
233	  org_unit: string;
234	}): Promise<User> {
235	  const salt = encryptionService.generateSalt();
236	  const passwordHash = await encryptionService.hashPassword(userData.password, salt);
237	
238	  const user: User = {
239	    user_id: crypto.randomUUID(),
240	    username: userData.username,
241	    password_hash: passwordHash,
242	    salt: salt.buffer as ArrayBuffer,
243	    role: userData.role,
244	    org_unit: userData.org_unit,
245	    failed_attempts: 0,
246	    locked_until: null,
247	    encryption_enabled: false,
248	    encryption_salt: null,
249	    _version: 1,
250	  };
251	
252	  await idbAccessLayer.put('users', user);
253	  return user;
254	}
255	
256	// ============================================================
257	// Export
258	// ============================================================
259	
260	export const authService = {
261	  login,
262	  logout,
263	  restoreSession,
264	  changePassword,
265	  initCrossTabSync,
266	  createUser,
267	};
268	
269	export default authService;
