2	// Roles
3	// ============================================================
4	
5	export const ROLES = ['SYSTEM_ADMIN', 'OPS_COORDINATOR', 'INSTRUCTOR', 'PARTICIPANT'] as const;
6	export type Role = (typeof ROLES)[number];
7	
8	// ============================================================
9	// Session (Auth)
10	// ============================================================
11	
12	export interface Session {
13	  user_id: string;
14	  role: Role;
15	  org_unit: string;
16	  token: string;
17	  expires_at: number;
18	}
19	
20	// ============================================================
