22	// ============================================================
23	
24	export interface User {
25	  user_id: string;
26	  username: string;
27	  password_hash: ArrayBuffer;
28	  salt: ArrayBuffer;
29	  role: Role;
30	  org_unit: string;
31	  failed_attempts: number;
32	  locked_until: number | null;
33	  encryption_enabled: boolean;
34	  encryption_salt: ArrayBuffer | null;
35	  _version: number;
36	}
37	
