39	  booking_id: string;
40	  room_id: string;
41	  user_id: string;
42	  start_time: number;
43	  end_time: number;
44	  requested_equipment: string[];
45	  participant_capacity: number;
46	  status: 'pending' | 'confirmed' | 'cancelled';
47	  created_at: number;
48	  _version: number;
49	}
50	
51	export interface SessionRecord {
52	  session_id: string;
53	  instructor_id: string;
54	  room_id: string;
55	  booking_id: string;
56	  title: string;
57	  start_time: number;
