472	async function del(store: string, key: string, userId?: string): Promise<void> {
473	  const database = getDb();
474	
475	  return new Promise<void>((resolve, reject) => {
476	    const tx = database.transaction(store, 'readwrite');
477	    const objectStore = tx.objectStore(store);
478	
479	    // If namespace filtering, verify ownership before deleting
480	    if (!SYSTEM_STORES.has(store) && userId) {
481	      const readRequest = objectStore.get(key);
482	      readRequest.onsuccess = () => {
483	        const existing = readRequest.result;
484	        if (!existing) {
485	          resolve();
486	          return;
487	        }
488	        if (existing.user_id && existing.user_id !== userId) {
489	          reject(new Error('Access denied: cannot delete record owned by another user'));
490	          return;
491	        }
492	        const deleteRequest = objectStore.delete(key);
493	        deleteRequest.onsuccess = () => {
494	          broadcastChange('record-deleted', store, key, undefined, userId);
495	          resolve();
496	        };
497	        deleteRequest.onerror = () => reject(deleteRequest.error);
498	      };
499	      readRequest.onerror = () => reject(readRequest.error);
500	    } else {
501	      const request = objectStore.delete(key);
502	      request.onsuccess = () => {
503	        broadcastChange('record-deleted', store, key, undefined, userId);
504	        resolve();
505	      };
506	      request.onerror = () => reject(request.error);
507	    }
508	  });
509	}
