306	function broadcastChange(type: 'record-updated' | 'record-deleted', store: string, recordId: string, version?: number, userId?: string): void {
307	  if (!dataSyncChannel) return;
308	  const message: DataSyncMessage = { type, store, record_id: recordId, version, user_id: userId };
309	  dataSyncChannel.postMessage(message);
310	}
