387	// eslint-disable-next-line @typescript-eslint/no-explicit-any
388	async function put(store: string, record: any, userId?: string): Promise<{ version: number }> {
389	  const database = getDb();
390	  const storeDef = STORE_DEFINITIONS[store];
391	  if (!storeDef) throw new Error(`Unknown store: ${store}`);
392	
393	  const keyPath = storeDef.keyPath;
394	  const recordKey = getKeyPathValue(record, keyPath);
395	  const isVersioned = VERSIONED_STORES.has(store);
396	
397	  return new Promise<{ version: number }>((resolve, reject) => {
398	    const tx = database.transaction(store, 'readwrite');
399	    const objectStore = tx.objectStore(store);
400	
401	    // If versioned, do optimistic locking
402	    if (isVersioned) {
403	      const readRequest = objectStore.get(recordKey);
404	
405	      readRequest.onsuccess = async () => {
406	        const existing = readRequest.result;
407	
408	        if (existing) {
409	          // Optimistic locking: compare versions
410	          const existingVersion = existing._version as number;
411	          const expectedVersion = record._version as number;
412	
413	          if (expectedVersion !== undefined && expectedVersion !== existingVersion) {
414	            tx.abort();
415	            reject(new VersionConflictError(
416	              `Version conflict on ${store}/${recordKey}: expected ${expectedVersion}, found ${existingVersion}`
417	            ));
418	            return;
419	          }
420	
421	          record._version = existingVersion + 1;
422	        } else {
423	          // New record
424	          record._version = 1;
425	        }
426	
427	        try {
428	          const toWrite = await maybeEncrypt({ ...record }, userId);
429	          const writeRequest = objectStore.put(toWrite);
430	
431	          writeRequest.onsuccess = () => {
432	            broadcastChange('record-updated', store, recordKey, record._version as number, userId);
433	            resolve({ version: record._version as number });
434	          };
435	
436	          writeRequest.onerror = () => reject(writeRequest.error);
437	        } catch (err) {
438	          tx.abort();
439	          reject(err);
440	        }
441	      };
442	
443	      readRequest.onerror = () => reject(readRequest.error);
444	    } else {
445	      // Non-versioned store: direct put
446	      (async () => {
447	        try {
448	          const toWrite = await maybeEncrypt({ ...record }, userId);
449	          const writeRequest = objectStore.put(toWrite);
450	
451	          writeRequest.onsuccess = () => {
452	            broadcastChange('record-updated', store, recordKey, undefined, userId);
453	            resolve({ version: 0 });
454	          };
455	
456	          writeRequest.onerror = () => reject(writeRequest.error);
457	        } catch (err) {
458	          tx.abort();
459	          reject(err);
460	        }
461	      })();
462	    }
463	
464	    tx.onerror = () => {
465	      if (tx.error?.name !== 'AbortError') {
466	        reject(tx.error);
467	      }
468	    };
469	  });
470	}
471	
472	async function del(store: string, key: string, userId?: string): Promise<void> {
473	  const database = getDb();
474	
475	  return new Promise<void>((resolve, reject) => {
476	    const tx = database.transaction(store, 'readwrite');
477	    const objectStore = tx.objectStore(store);
478	
479	    // If namespace filtering, verify ownership before deleting
480	    if (!SYSTEM_STORES.has(store) && userId) {
481	      const readRequest = objectStore.get(key);
482	      readRequest.onsuccess = () => {
483	        const existing = readRequest.result;
484	        if (!existing) {
485	          resolve();
486	          return;
487	        }
488	        if (existing.user_id && existing.user_id !== userId) {
489	          reject(new Error('Access denied: cannot delete record owned by another user'));
490	          return;
491	        }
492	        const deleteRequest = objectStore.delete(key);
493	        deleteRequest.onsuccess = () => {
494	          broadcastChange('record-deleted', store, key, undefined, userId);
495	          resolve();
496	        };
497	        deleteRequest.onerror = () => reject(deleteRequest.error);
498	      };
499	      readRequest.onerror = () => reject(readRequest.error);
500	    } else {
501	      const request = objectStore.delete(key);
502	      request.onsuccess = () => {
503	        broadcastChange('record-deleted', store, key, undefined, userId);
504	        resolve();
505	      };
506	      request.onerror = () => reject(request.error);
507	    }
508	  });
509	}
