511	/**
512	 * Execute a function within an IndexedDB transaction spanning one or more stores.
513	 * The function receives a helper object with get/getAll/put/delete methods scoped to the transaction.
514	 * All operations within the function are atomic.
515	 */
516	async function transaction<T>(
517	  storeNames: string[],
518	  mode: IDBTransactionMode,
519	  fn: (helpers: TransactionHelpers) => Promise<T>,
520	): Promise<T> {
521	  const database = getDb();
522	
523	  return new Promise<T>((resolve, reject) => {
524	    const tx = database.transaction(storeNames, mode);
525	    let result: T;
526	    let completed = false;
527	
528	    const helpers: TransactionHelpers = {
529	      getStore(storeName: string): IDBObjectStore {
530	        return tx.objectStore(storeName);
531	      },
532	
533	      get<R = Record<string, unknown>>(storeName: string, key: string): Promise<R | undefined> {
534	        return new Promise((res, rej) => {
535	          const store = tx.objectStore(storeName);
536	          const request = store.get(key);
537	          request.onsuccess = () => res(request.result as R | undefined);
538	          request.onerror = () => rej(request.error);
539	        });
540	      },
541	
542	      getAll<R = Record<string, unknown>>(storeName: string, indexName?: string, query?: IDBKeyRange | IDBValidKey): Promise<R[]> {
543	        return new Promise((res, rej) => {
544	          const store = tx.objectStore(storeName);
545	          const source = indexName ? store.index(indexName) : store;
546	          const request = source.getAll(query);
547	          request.onsuccess = () => res(request.result as R[]);
548	          request.onerror = () => rej(request.error);
549	        });
550	      },
551	
552	      put(storeName: string, record: Record<string, unknown>): Promise<void> {
553	        return new Promise((res, rej) => {
554	          const store = tx.objectStore(storeName);
555	          const request = store.put(record);
556	          request.onsuccess = () => res();
557	          request.onerror = () => rej(request.error);
558	        });
559	      },
560	
561	      delete(storeName: string, key: string): Promise<void> {
562	        return new Promise((res, rej) => {
563	          const store = tx.objectStore(storeName);
564	          const request = store.delete(key);
565	          request.onsuccess = () => res();
566	          request.onerror = () => rej(request.error);
567	        });
568	      },
569	
570	      abort(): void {
571	        tx.abort();
572	      },
573	    };
574	
575	    tx.oncomplete = () => {
576	      completed = true;
577	      resolve(result);
578	    };
579	
580	    tx.onerror = () => {
581	      if (!completed) {
582	        reject(tx.error);
583	      }
584	    };
585	
586	    tx.onabort = () => {
587	      if (!completed) {
588	        reject(tx.error || new Error('Transaction aborted'));
589	      }
590	    };
591	
592	    // Execute the user function
593	    fn(helpers)
594	      .then((r) => {
595	        result = r;
596	      })
597	      .catch((err) => {
598	        try { tx.abort(); } catch { /* already aborted */ }
599	        reject(err);
600	      });
601	  });
602	}
