278	
279	function setEncryptionHooks(
280	  encrypt: (data: unknown, userId: string) => Promise<unknown>,
281	  decrypt: (data: unknown, userId: string) => Promise<unknown>,
282	): void {
283	  encryptHook = encrypt;
284	  decryptHook = decrypt;
