293	// Internal Helpers
294	// ============================================================
295	
296	async function maybeEncrypt(record: Record<string, unknown>, userId?: string): Promise<Record<string, unknown>> {
297	  if (!encryptHook || !userId || !isEncryptionEnabled(userId)) return record;
298	  return (await encryptHook(record, userId)) as Record<string, unknown>;
299	}
300	
301	async function maybeDecrypt(record: Record<string, unknown>, userId?: string): Promise<Record<string, unknown>> {
302	  if (!decryptHook || !userId || !isEncryptionEnabled(userId)) return record;
303	  return (await decryptHook(record, userId)) as Record<string, unknown>;
304	}
