318	// ============================================================
319	
320	async function get<T = Record<string, unknown>>(store: string, key: string, userId?: string): Promise<T | undefined> {
321	  const database = getDb();
322	
323	  return new Promise<T | undefined>((resolve, reject) => {
324	    const tx = database.transaction(store, 'readonly');
325	    const objectStore = tx.objectStore(store);
326	    const request = objectStore.get(key);
327	
328	    request.onsuccess = async () => {
329	      const record = request.result;
330	      if (!record) {
331	        resolve(undefined);
332	        return;
333	      }
334	
335	      // Namespace filtering: if not a system store, check user_id
336	      if (!SYSTEM_STORES.has(store) && userId && record.user_id && record.user_id !== userId) {
337	        resolve(undefined);
338	        return;
339	      }
340	
341	      try {
342	        const decrypted = await maybeDecrypt(record, userId);
343	        resolve(decrypted as T);
344	      } catch (err) {
345	        reject(err);
346	      }
347	    };
348	
349	    request.onerror = () => reject(request.error);
350	  });
351	}
