105	// ============================================================
106	// 4. retract
107	// ============================================================
108	
109	async function retract(messageId: string): Promise<void> {
110	  rbacService.checkPermission('message:retract');
111	  const message = await getMessageOrThrow(messageId);
112	
113	  message.status = 'retracted';
114	
115	  // Retain record + receipts for audit
116	  await idbAccessLayer.put('messages', message);
117	}
118	
119	// ============================================================
120	// 5. pin
121	// ============================================================
122	
123	async function pin(messageId: string, pinned: boolean): Promise<void> {
124	  rbacService.checkPermission('message:pin');
125	  const message = await getMessageOrThrow(messageId);
126	
127	  message.pinned = pinned;
128	
129	  await idbAccessLayer.put('messages', message);
130	}
131	
132	// ============================================================
133	// 6. recordReadReceipt
134	// ============================================================
135	
136	async function recordReadReceipt(messageId: string, userId: string): Promise<void> {
137	  const existing = await idbAccessLayer.getAll<ReadReceipt>(
138	    'read_receipts',
139	    'idx_message_user',
140	    [messageId, userId],
141	  );
142	
143	  if (existing.length > 0) {
144	    return;
145	  }
146	
147	  const receipt: ReadReceipt = {
148	    receipt_id: crypto.randomUUID(),
149	    message_id: messageId,
150	    user_id: userId,
151	    read_at: Date.now(),
152	  };
153	
154	  await idbAccessLayer.put('read_receipts', receipt);
155	}
156	
157	// ============================================================
158	// 7. getAnalytics
159	// ============================================================
160	
161	async function getAnalytics(messageId: string): Promise<{ uniqueOpens: number; timeToFirstRead: number | null }> {
162	  const receipts = await idbAccessLayer.getAll<ReadReceipt>('read_receipts', 'idx_message', messageId);
163	
164	  const uniqueOpens = receipts.length;
165	
166	  if (uniqueOpens === 0) {
167	    return { uniqueOpens: 0, timeToFirstRead: null };
168	  }
169	
170	  const message = await getMessageOrThrow(messageId);
171	
172	  if (message.published_at === null) {
173	    return { uniqueOpens, timeToFirstRead: null };
174	  }
175	
176	  const earliestRead = Math.min(...receipts.map((r) => r.read_at));
177	  const timeToFirstRead = earliestRead - message.published_at;
178	
179	  return { uniqueOpens, timeToFirstRead };
180	}
181	
182	// ============================================================
183	// 8. getInbox
184	// ============================================================
185	
186	async function getInbox(userId: string, filters: InboxFilters): Promise<PaginatedMessages> {
187	  let messages = await getVisibleMessages(userId);
188	
189	  // Filter by category if specified
190	  if (filters.category) {
191	    messages = messages.filter((m) => m.category === filters.category);
192	  }
193	
194	  // Sort: pinned first, then by published_at descending
195	  messages.sort((a, b) => {
196	    if (a.pinned !== b.pinned) {
197	      return a.pinned ? -1 : 1;
198	    }
199	    return (b.published_at ?? 0) - (a.published_at ?? 0);
200	  });
201	
202	  const total = messages.length;
203	  const page = filters.page ?? 0;
204	  const pageSize = filters.pageSize ?? 20;
205	  const start = page * pageSize;
206	  const paged = messages.slice(start, start + pageSize);
207	
208	  return { messages: paged, total, page, pageSize };
209	}
210	
211	// ============================================================
212	// 9. search
213	// ============================================================
214	
215	async function search(query: string, userId: string): Promise<PaginatedMessages> {
216	  let messages = await getVisibleMessages(userId);
217	
218	  const lowerQuery = query.toLowerCase();
219	  messages = messages.filter(
220	    (m) =>
221	      m.title.toLowerCase().includes(lowerQuery) ||
222	      m.body.toLowerCase().includes(lowerQuery),
223	  );
224	
225	  // Sort by recency (published_at desc)
226	  messages.sort((a, b) => (b.published_at ?? 0) - (a.published_at ?? 0));
227	
228	  return { messages, total: messages.length, page: 0, pageSize: messages.length };
229	}
230	
231	// ============================================================
232	// 10. getMessage
233	// ============================================================
234	
235	async function getMessage(messageId: string): Promise<Message | undefined> {
236	  return idbAccessLayer.get<Message>('messages', messageId);
237	}
238	
239	// ============================================================
240	// 11. getUnreadCount
241	// ============================================================
242	
243	async function getUnreadCount(userId: string): Promise<number> {
244	  const visibleMessages = await getVisibleMessages(userId);
245	
246	  const userReceipts = await idbAccessLayer.getAll<ReadReceipt>('read_receipts', 'idx_user', userId);
247	  const readMessageIds = new Set(userReceipts.map((r) => r.message_id));
248	
249	  return visibleMessages.filter((m) => !readMessageIds.has(m.message_id)).length;
250	}
251	
252	// ============================================================
253	// Export
254	// ============================================================
255	
256	export const messageCenterService = {
257	  compose,
258	  publish,
259	  schedule,
260	  retract,
261	  pin,
262	  recordReadReceipt,
263	  getAnalytics,
264	  getInbox,
265	  search,
266	  getMessage,
267	  getUnreadCount,
268	};
269	
270	export default messageCenterService;
