8	function getISOWeekLabel(timestamp: number): string {
9	  const date = new Date(timestamp);
10	  // Thursday-based ISO week calculation
11	  const tmp = new Date(date.getTime());
12	  tmp.setUTCHours(0, 0, 0, 0);
13	  // Set to nearest Thursday: current date + 4 - current day number (Monday=1 .. Sunday=7)
14	  tmp.setUTCDate(tmp.getUTCDate() + 4 - (tmp.getUTCDay() || 7));
15	  const yearStart = new Date(Date.UTC(tmp.getUTCFullYear(), 0, 1));
16	  const weekNo = Math.ceil(((tmp.getTime() - yearStart.getTime()) / 86400000 + 1) / 7);
17	  return `${tmp.getUTCFullYear()}-W${String(weekNo).padStart(2, '0')}`;
18	}
19	
20	function getBucketLabel(timestamp: number, granularity: 'daily' | 'weekly' | 'monthly'): string {
21	  const date = new Date(timestamp);
22	  if (granularity === 'daily') {
23	    const y = date.getUTCFullYear();
24	    const m = String(date.getUTCMonth() + 1).padStart(2, '0');
25	    const d = String(date.getUTCDate()).padStart(2, '0');
26	    return `${y}-${m}-${d}`;
27	  }
28	  if (granularity === 'weekly') {
29	    return getISOWeekLabel(timestamp);
30	  }
31	  // monthly
32	  const y = date.getUTCFullYear();
33	  const m = String(date.getUTCMonth() + 1).padStart(2, '0');
34	  return `${y}-${m}`;
35	}
