41	async function getBookingConversionRate(period: DateRange): Promise<number | 'N/A'> {
42	  const bookings = await idbAccessLayer.getAll<Booking>('bookings');
43	  const filtered = bookings.filter((b) => {
44	    const createdAt = b.created_at ?? 0;
45	    return createdAt >= period.start && createdAt <= period.end;
46	  });
47	
48	  const total = filtered.length;
49	  if (total === 0) return 'N/A';
50	
51	  const confirmed = filtered.filter((b) => b.status === 'confirmed').length;
52	  return confirmed / total;
53	}
