55	async function getNoShowRate(period: DateRange): Promise<number | 'N/A'> {
56	  const records = await idbAccessLayer.getAll<Attendance>('attendance');
57	  const filtered = records.filter((r) => {
58	    const recordedAt = r.recorded_at ?? 0;
59	    return recordedAt >= period.start && recordedAt <= period.end;
60	  });
61	
62	  const total = filtered.length;
63	  if (total === 0) return 'N/A';
64	
65	  const noShows = filtered.filter((r) => r.attendance_status === 'no-show').length;
66	  return noShows / total;
67	}
