69	async function getSlotUtilization(roomId: string, period: DateRange): Promise<number> {
70	  const bookings = await idbAccessLayer.getAll<Booking>('bookings');
71	  const filtered = bookings.filter((b) => {
72	    const status = b.status ?? 'pending';
73	    return (
74	      b.room_id === roomId &&
75	      b.start_time >= period.start &&
76	      b.end_time <= period.end &&
77	      status !== 'cancelled'
78	    );
79	  });
80	
81	  const bookedHours = filtered.reduce((sum, b) => {
82	    return sum + (b.end_time - b.start_time) / (1000 * 60 * 60);
83	  }, 0);
84	
85	  const availableHours = (period.end - period.start) / (1000 * 60 * 60);
86	  if (availableHours <= 0) return 0;
87	
88	  const ratio = bookedHours / availableHours;
89	  return Math.max(0, Math.min(1, ratio));
90	}
