118	async function getBookingTrend(
119	  period: DateRange,
120	  granularity: 'daily' | 'weekly' | 'monthly',
121	): Promise<Array<{ label: string; total: number; confirmed: number }>> {
122	  const bookings = await idbAccessLayer.getAll<Booking>('bookings');
123	  const filtered = bookings.filter((b) => {
124	    const createdAt = b.created_at ?? 0;
125	    return createdAt >= period.start && createdAt <= period.end;
126	  });
127	
128	  const buckets = new Map<string, { total: number; confirmed: number }>();
129	
130	  for (const b of filtered) {
131	    const createdAt = b.created_at ?? 0;
132	    const label = getBucketLabel(createdAt, granularity);
133	    const bucket = buckets.get(label) ?? { total: 0, confirmed: 0 };
134	    bucket.total++;
135	    if (b.status === 'confirmed') {
136	      bucket.confirmed++;
137	    }
138	    buckets.set(label, bucket);
139	  }
140	
141	  const result: Array<{ label: string; total: number; confirmed: number }> = [];
142	  for (const [label, data] of buckets) {
143	    result.push({ label, total: data.total, confirmed: data.confirmed });
144	  }
145	
146	  result.sort((a, b) => (a.label < b.label ? -1 : a.label > b.label ? 1 : 0));
147	  return result;
148	}
