4	// ============================================================
5	// Helper: DND Configuration
6	// ============================================================
7	
8	interface DndConfig {
9	  start: string;
10	  end: string;
11	}
12	
13	function parseDndConfig(): DndConfig {
14	  try {
15	    const raw = localStorage.getItem('dnd_config');
16	    if (raw) {
17	      return JSON.parse(raw) as DndConfig;
18	    }
19	  } catch {
20	    // fall through to default
21	  }
22	  return { start: '22:00', end: '07:00' };
23	}
24	
25	function parseTimeString(time: string): { hour: number; minute: number } {
26	  const [hour, minute] = time.split(':').map(Number);
27	  return { hour, minute };
28	}
29	
30	function currentMinuteOfDay(): number {
31	  const now = new Date();
32	  return now.getHours() * 60 + now.getMinutes();
33	}
34	
35	// ============================================================
36	// 5. isDndActive
37	// ============================================================
38	
39	function isDndActive(): boolean {
40	  const config = parseDndConfig();
41	  const start = parseTimeString(config.start);
42	  const end = parseTimeString(config.end);
43	  const startMinutes = start.hour * 60 + start.minute;
44	  const endMinutes = end.hour * 60 + end.minute;
45	  const now = currentMinuteOfDay();
46	
47	  if (startMinutes > endMinutes) {
48	    // Overnight window: e.g. 22:00 - 07:00
49	    return now >= startMinutes || now < endMinutes;
50	  } else {
51	    return now >= startMinutes && now < endMinutes;
52	  }
53	}
54	
55	// ============================================================
56	// 6. getDndEndTime
57	// ============================================================
58	
59	function getDndEndTime(): number {
60	  const config = parseDndConfig();
61	  const end = parseTimeString(config.end);
62	
63	  const now = new Date();
64	  const todayEnd = new Date(now);
65	  todayEnd.setHours(end.hour, end.minute, 0, 0);
66	
67	  // If todayEnd is in the future, that's the next end time
68	  if (todayEnd.getTime() > now.getTime()) {
69	    return todayEnd.getTime();
70	  }
71	
72	  // Otherwise, it's tomorrow's end time
73	  todayEnd.setDate(todayEnd.getDate() + 1);
74	  return todayEnd.getTime();
75	}
