100	// ============================================================
101	// 2. resolveTemplateVariables
102	// ============================================================
103	
104	async function resolveTemplateVariables(
105	  template: string,
106	  linkedType?: string,
107	  linkedId?: string,
108	): Promise<string> {
109	  let result = template;
110	  const vars = template.match(/\{\{\w+\}\}/g) || [];
111	  const resolved = new Set<string>();
112	
113	  // {{room_name}}
114	  if (vars.some((v) => v === '{{room_name}}')) {
115	    let roomName = '[Unknown]';
116	    try {
117	      if (linkedType === 'room' && linkedId) {
118	        const room = await idbAccessLayer.get<Room>('rooms', linkedId);
119	        roomName = room ? room.name : '[Room removed]';
120	      } else if (linkedType === 'booking' && linkedId) {
121	        const booking = await idbAccessLayer.get<{ room_id: string }>('bookings', linkedId);
122	        if (booking) {
123	          const room = await idbAccessLayer.get<Room>('rooms', booking.room_id);
124	          roomName = room ? room.name : '[Room removed]';
125	        } else {
126	          roomName = '[Room removed]';
127	        }
128	      }
129	    } catch {
130	      roomName = '[Room removed]';
131	    }
132	    result = result.replace(/\{\{room_name\}\}/g, roomName);
133	    resolved.add('{{room_name}}');
134	  }
135	
136	  // {{start_time}}
137	  if (vars.some((v) => v === '{{start_time}}')) {
138	    let startTime = '[Unknown time]';
139	    try {
140	      if ((linkedType === 'session' || linkedType === 'booking') && linkedId) {
141	        if (linkedType === 'session') {
142	          const session = await idbAccessLayer.get<SessionRecord>('sessions', linkedId);
143	          if (session) {
144	            startTime = new Date(session.start_time).toLocaleString();
145	          }
146	        } else {
147	          const booking = await idbAccessLayer.get<{ start_time: number }>('bookings', linkedId);
148	          if (booking) {
149	            startTime = new Date(booking.start_time).toLocaleString();
150	          }
151	        }
152	      }
153	    } catch {
154	      startTime = '[Unknown time]';
155	    }
156	    result = result.replace(/\{\{start_time\}\}/g, startTime);
157	    resolved.add('{{start_time}}');
158	  }
159	
160	  // {{coordinator}}
161	  if (vars.some((v) => v === '{{coordinator}}')) {
162	    let coordinator = '[Unknown coordinator]';
163	    try {
164	      if (linkedType === 'session' && linkedId) {
165	        const session = await idbAccessLayer.get<SessionRecord>('sessions', linkedId);
166	        if (session) {
167	          const instructor = await idbAccessLayer.get<{ username: string }>('users', session.instructor_id);
168	          coordinator = instructor ? instructor.username : '[Unknown coordinator]';
169	        }
170	      }
171	    } catch {
172	      coordinator = '[Unknown coordinator]';
173	    }
174	    result = result.replace(/\{\{coordinator\}\}/g, coordinator);
175	    resolved.add('{{coordinator}}');
176	  }
177	
178	  // Replace any remaining unresolved template variables with [Unknown]
179	  result = result.replace(/\{\{\w+\}\}/g, '[Unknown]');
180	
181	  return result;
182	}
