184	// ============================================================
185	// 3. deliverPending
186	// ============================================================
187	
188	async function deliverPending(): Promise<void> {
189	  const allReminders = await idbAccessLayer.getAll<Reminder>('reminders', 'idx_status', 'pending');
190	  const now = Date.now();
191	
192	  // Filter: fire_at <= now, or fire_at is null and trigger_type='event'
193	  const due = allReminders.filter((r) => {
194	    if (r.fire_at !== null && r.fire_at <= now) return true;
195	    if (r.fire_at === null && r.trigger_type === 'event') return true;
196	    return false;
197	  });
198	
199	  // Collect recently delivered reminders for dedup check
200	  const allDeliveredReminders = await idbAccessLayer.getAll<Reminder>('reminders', 'idx_status', 'delivered');
201	  const recentDelivered = allDeliveredReminders.filter(
202	    (r) => r.trigger_time !== null && r.trigger_time > now - 60_000,
203	  );
204	
205	  for (const reminder of due) {
206	    // Check DND
207	    if (isDndActive()) {
208	      reminder.status = 'queued';
209	      reminder.fire_at = getDndEndTime();
210	      await idbAccessLayer.put('reminders', reminder);
211	
212	      const log: SendLog = {
213	        log_id: crypto.randomUUID(),
214	        reminder_id: reminder.reminder_id,
215	        user_id: reminder.user_id,
216	        sent_at: Date.now(),
217	        delivery_status: 'suppressed_dnd',
218	      };
219	      await idbAccessLayer.put('send_logs', log);
220	      continue;
221	    }
222	
223	    // Resolve template first for dedup comparison
224	    const resolvedText = await resolveTemplateVariables(
225	      reminder.template,
226	      reminder.linked_entity_type || undefined,
227	      reminder.linked_entity_id || undefined,
228	    );
229	
230	    // Check deduplication using original trigger_time
231	    const isDuplicate = recentDelivered.some(
232	      (r) =>
233	        r.user_id === reminder.user_id &&
234	        r.resolved_text === resolvedText,
235	    );
236	    if (isDuplicate) {
237	      continue;
238	    }
239	
240	    // Before delivering event-triggered reminders: check if linked session is cancelled
241	    if (reminder.trigger_type === 'event' && reminder.linked_entity_type === 'session' && reminder.linked_entity_id) {
242	      const session = await idbAccessLayer.get<SessionRecord>('sessions', reminder.linked_entity_id);
243	      if (session && session.status === 'cancelled') {
244	        continue;
245	      }
246	    }
247	
248	    // Deliver
249	    reminder.status = 'delivered';
250	    reminder.resolved_text = resolvedText;
251	    await idbAccessLayer.put('reminders', reminder);
252	
253	    const log: SendLog = {
254	      log_id: crypto.randomUUID(),
255	      reminder_id: reminder.reminder_id,
256	      user_id: reminder.user_id,
257	      sent_at: Date.now(),
258	      delivery_status: 'delivered',
259	    };
260	    await idbAccessLayer.put('send_logs', log);
261	  }
262	}
263	
264	// ============================================================
265	// 4. deliverQueuedBatch
266	// ============================================================
267	
268	async function deliverQueuedBatch(): Promise<void> {
269	  const queued = await idbAccessLayer.getAll<Reminder>('reminders', 'idx_status', 'queued');
270	
271	  if (isDndActive()) {
272	    return;
273	  }
274	
275	  const batches: Reminder[][] = [];
276	  for (let i = 0; i < queued.length; i += 10) {
277	    batches.push(queued.slice(i, i + 10));
278	  }
279	
280	  for (let batchIndex = 0; batchIndex < batches.length; batchIndex++) {
281	    if (batchIndex > 0) {
282	      await new Promise<void>((resolve) => setTimeout(resolve, 0));
283	    }
284	
285	    for (const reminder of batches[batchIndex]) {
286	      const resolvedText = await resolveTemplateVariables(
287	        reminder.template,
288	        reminder.linked_entity_type || undefined,
289	        reminder.linked_entity_id || undefined,
290	      );
291	
292	      reminder.status = 'delivered';
293	      reminder.resolved_text = resolvedText;
294	      await idbAccessLayer.put('reminders', reminder);
295	
296	      const log: SendLog = {
297	        log_id: crypto.randomUUID(),
298	        reminder_id: reminder.reminder_id,
299	        user_id: reminder.user_id,
300	        sent_at: Date.now(),
301	        delivery_status: 'delivered',
302	      };
303	      await idbAccessLayer.put('send_logs', log);
304	    }
305	  }
306	}
