  import { onMount } from 'svelte';
  import { analyticsService } from '../../lib/services/analyticsService';
  import type { DateRange } from '../../lib/types';

  let startDate = $state('');
  let endDate = $state('');
  let granularity: 'daily' | 'weekly' | 'monthly' = $state('daily');
  let loading = $state(true);
  let error = $state('');

  let trendData: Array<{ label: string; total: number; confirmed: number }> = $state([]);

  let maxTotal = $derived(Math.max(1, ...trendData.map((d) => d.total)));

  function defaultPeriod(): { start: string; end: string } {
    const now = new Date();
    const end = now.toISOString().slice(0, 10);
    const past = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
    const start = past.toISOString().slice(0, 10);
    return { start, end };
  }

  function buildDateRange(): DateRange {
    const s = startDate ? new Date(startDate).getTime() : Date.now() - 30 * 24 * 60 * 60 * 1000;
    const e = endDate ? new Date(endDate + 'T23:59:59').getTime() : Date.now();
    return { start: s, end: e };
  }

  function conversionRate(total: number, confirmed: number): string {
    if (total === 0) return 'N/A';
    return ((confirmed / total) * 100).toFixed(1) + '%';
  }

  async function loadData() {
    loading = true;
    error = '';
    try {
      const period = buildDateRange();
      trendData = await analyticsService.getBookingTrend(period, granularity);
    } catch (e: any) {
      error = e.message ?? 'Failed to load booking trend';
    } finally {
      loading = false;
    }
  }

  onMount(() => {
    const defaults = defaultPeriod();
    startDate = defaults.start;
    endDate = defaults.end;
    loadData();
  });
</script>

