          <option value="weekly">Weekly</option>
          <option value="monthly">Monthly</option>
        </select>
      </label>
      <button class="btn btn-primary" onclick={loadData} disabled={loading}>
        {loading ? 'Loading...' : 'Apply'}
      </button>
