/**
 * Masks a string value showing only the last 4 characters.
 * Format: ****1234
 * If value is shorter than 4 chars, mask entirely: ****
 */
export function maskSensitiveField(value: string): string {
  if (!value || value.length <= 4) return '****';
  return '****' + value.slice(-4);
}

/**
 * Masks a number, showing only last 4 digits.
 * E.g., 123456789 → ****6789
 */
export function maskNumber(value: number): string {
  return maskSensitiveField(String(value));
}
```

## File 2: `/Users/minilik/projects/eaglepoint/w1t116/repo/src/lib/utils/consistencyChecker.ts`

Startup consistency checker that validates referential integrity between IndexedDB stores.

Imports:
```typescript
import { idbAccessLayer } from '../services/idbAccessLayer';
```

idbAccessLayer has: `get(store, key)`, `getAll(store)`.

Implement:

### `runConsistencyCheck(): Promise<ConsistencyReport>`

```typescript
interface ConsistencyIssue {
  store: string;
  record_id: string;
  issue: string;
}

interface ConsistencyReport {
  issues: ConsistencyIssue[];
  checkedAt: number;
  storesChecked: number;
}
```

Checks:
1. **Registrations → Sessions**: For each registration, verify the referenced session_id exists in sessions store. If not, flag "Registration references non-existent session".
2. **Payments → Bills**: For each payment, verify bill_id exists in bills store. If not, flag.
3. **Bookings → Rooms**: For each booking, verify room_id exists in rooms store. If not, flag.
4. **Attendance → Sessions**: For each attendance record, verify session_id exists. If not, flag.
5. **Attendance → Registrations**: For each attendance record, verify there's a registration for that participant+session. (This is a soft check — flag as warning only.)
6. **Read Receipts → Messages**: For each read receipt, verify message_id exists. If not, flag.

Do NOT auto-delete orphaned records. Just report.

Return `{issues, checkedAt: Date.now(), storesChecked: 6}`.

Export: `export { runConsistencyCheck, type ConsistencyReport, type ConsistencyIssue }`.

Also implement:

### `operationQueue` in `/Users/minilik/projects/eaglepoint/w1t116/repo/src/lib/utils/operationQueue.ts`

A per-tab in-memory queue that serializes IndexedDB mutations.

```typescript
interface QueuedOperation<T> {
  execute: () => Promise<T>;
  resolve: (value: T) => void;
  reject: (error: any) => void;
}

class OperationQueue {
  private queue: QueuedOperation<any>[] = [];
  private processing = false;

  async enqueue<T>(operation: () => Promise<T>): Promise<T> {
    return new Promise<T>((resolve, reject) => {
      this.queue.push({ execute: operation, resolve, reject });
      this.processNext();
    });
  }

  private async processNext(): Promise<void> {
    if (this.processing || this.queue.length === 0) return;
    this.processing = true;

    const op = this.queue.shift()!;
    try {
      const result = await op.execute();
      op.resolve(result);
    } catch (err) {
      op.reject(err);
    } finally {
      this.processing = false;
      this.processNext();
    }
  }
}

export const operationQueue = new OperationQueue();
export default operationQueue;
```

